<template>
  <div
    class="custom-select"
    :tabindex="tabindex"
    :class="{'is-mobile': isMobile}"
    @click.self="toggleisCustomOptionsShown"
    @blur="isCustomOptionsShown = false"
    @keyup.self.up="pressKeyUp"
    @keyup.self.down="pressKeyDown"
    @keyup.self.enter="toggleisCustomOptionsShown"
  >
    <select
      :value="label ? value[label] : value"
      @input="updateValue(options[$event.target.selectedIndex])"
    >
      <option
        v-for="option in options"
        :key="option.locale"
      >
        {{ label ? option[label] : option }}
      </option>
    </select>

    <!-- custom options that appear only on desktop browser: -->
    <div
      v-if="isCustomOptionsShown && !isMobile"
      class="custom-select__options"
    >
      <div
        v-for="(option, index) in options"
        :key="option.locale"
        class="custom-select__options__item"
        :class="{'active': selectedIndex === index }"
        @click="selectCustomOption(option)"
      >
        {{ label ? option[label] : option }}
      </div>
    </div>
  </div>
</template>

<script>
export default {
  props: {
    value: {
      type: [Number, String, Object],
      required: true,
    },

    options: {
      type: Array,
      required: true
    },

    tabindex: {
      // tabindex is used for make @blur working when click outside .custom-select
      type: Number,
      required: false,
      default: 0
    },

    label: {
      // label should be provide if options is an array from objects
      type: String,
      required: false,
      default: ''
    },

    trackBy: {
      // trackBy should be provide if options is an array from objects
      type: String,
      required: false,
      default: ''
    }
  },
  data() {
    return {
      isCustomOptionsShown: false,
    }
  },
  computed: {
    isMobile() {
    // detect if it's mobile browser
    let uaOrVendor = window.navigator.userAgent || window.navigator.vendor || window.opera;
    /* eslint-disable-next-line */
    return (/(android|bb\d+|meego).+mobile|avantgo|bada\/|blackberry|blazer|compal|elaine|fennec|hiptop|iemobile|ip(hone|od)|iris|kindle|lge |maemo|midp|mmp|mobile.+firefox|netfront|opera m(ob|in)i|palm( os)?|phone|p(ixi|re)\/|plucker|pocket|psp|series(4|6)0|symbian|treo|up\.(browser|link)|vodafone|wap|windows ce|xda|xiino/i.test(uaOrVendor)||/1207|6310|6590|3gso|4thp|50[1-6]i|770s|802s|a wa|abac|ac(er|oo|s\-)|ai(ko|rn)|al(av|ca|co)|amoi|an(ex|ny|yw)|aptu|ar(ch|go)|as(te|us)|attw|au(di|\-m|r |s )|avan|be(ck|ll|nq)|bi(lb|rd)|bl(ac|az)|br(e|v)w|bumb|bw\-(n|u)|c55\/|capi|ccwa|cdm\-|cell|chtm|cldc|cmd\-|co(mp|nd)|craw|da(it|ll|ng)|dbte|dc\-s|devi|dica|dmob|do(c|p)o|ds(12|\-d)|el(49|ai)|em(l2|ul)|er(ic|k0)|esl8|ez([4-7]0|os|wa|ze)|fetc|fly(\-|_)|g1 u|g560|gene|gf\-5|g\-mo|go(\.w|od)|gr(ad|un)|haie|hcit|hd\-(m|p|t)|hei\-|hi(pt|ta)|hp( i|ip)|hs\-c|ht(c(\-| |_|a|g|p|s|t)|tp)|hu(aw|tc)|i\-(20|go|ma)|i230|iac( |\-|\/)|ibro|idea|ig01|ikom|im1k|inno|ipaq|iris|ja(t|v)a|jbro|jemu|jigs|kddi|keji|kgt( |\/)|klon|kpt |kwc\-|kyo(c|k)|le(no|xi)|lg( g|\/(k|l|u)|50|54|\-[a-w])|libw|lynx|m1\-w|m3ga|m50\/|ma(te|ui|xo)|mc(01|21|ca)|m\-cr|me(rc|ri)|mi(o8|oa|ts)|mmef|mo(01|02|bi|de|do|t(\-| |o|v)|zz)|mt(50|p1|v )|mwbp|mywa|n10[0-2]|n20[2-3]|n30(0|2)|n50(0|2|5)|n7(0(0|1)|10)|ne((c|m)\-|on|tf|wf|wg|wt)|nok(6|i)|nzph|o2im|op(ti|wv)|oran|owg1|p800|pan(a|d|t)|pdxg|pg(13|\-([1-8]|c))|phil|pire|pl(ay|uc)|pn\-2|po(ck|rt|se)|prox|psio|pt\-g|qa\-a|qc(07|12|21|32|60|\-[2-7]|i\-)|qtek|r380|r600|raks|rim9|ro(ve|zo)|s55\/|sa(ge|ma|mm|ms|ny|va)|sc(01|h\-|oo|p\-)|sdk\/|se(c(\-|0|1)|47|mc|nd|ri)|sgh\-|shar|sie(\-|m)|sk\-0|sl(45|id)|sm(al|ar|b3|it|t5)|so(ft|ny)|sp(01|h\-|v\-|v )|sy(01|mb)|t2(18|50)|t6(00|10|18)|ta(gt|lk)|tcl\-|tdg\-|tel(i|m)|tim\-|t\-mo|to(pl|sh)|ts(70|m\-|m3|m5)|tx\-9|up(\.b|g1|si)|utst|v400|v750|veri|vi(rg|te)|vk(40|5[0-3]|\-v)|vm40|voda|vulc|vx(52|53|60|61|70|80|81|83|85|98)|w3c(\-| )|webc|whit|wi(g |nc|nw)|wmlb|wonu|x700|yas\-|your|zeto|zte\-/i.test(uaOrVendor.substr(0,4)));
    },
    selectedIndex(){
      return this.options.findIndex((item) => {
        if(this.trackBy) {
          return item[this.trackBy] === this.value[this.trackBy]
        }
        return item === this.value
      })
    },
  },

  methods: {
    toggleisCustomOptionsShown() {
      this.isCustomOptionsShown = !this.isCustomOptionsShown;
    },

    updateValue(value) {
      this.$emit('input', value)
    },
    selectCustomOption(value) {
      // this.$emit('input', value)
      this.updateValue(value);
      this.isCustomOptionsShown = false;
    },

    pressKeyUp() {
      this.selectedIndex > 0 && this.updateValue(this.options[this.selectedIndex-1]);
    },
    pressKeyDown() {
      this.selectedIndex < this.options.length - 1 && this.updateValue(this.options[this.selectedIndex+1]);
    }
  }
}
</script>

<style lang="scss" scoped>
  .custom-select {
    $select-padding-x: 15px;
    $select-padding-y: 10px;
    $select-arrows-width: 8px;
    $select-arrows-height: 10px;
    $select-arrow-color: #cccccc;

    width: 100%;
    outline: none;
    display: flex;
    flex-wrap: wrap;
    position: relative;

    &:hover {
      cursor: pointer;
    }

    select {
      pointer-events: none;
      flex: 0 0 100%;
      max-width: 100%;
      outline: none;
      background-image: url("data:image/svg+xml;charset=utf-8,%3Csvg xmlns='http://www.w3.org/2000/svg' width='4' height='5'%3E%3Cpath fill='%23e4e4e6' d='M2 0L0 2h4zm0 5L0 3h4z'/%3E%3C/svg%3E"), linear-gradient(to bottom, #393E41 0%, #36373b 50%, #333438 100%);
      background-repeat: no-repeat;
      background-size: $select-arrows-width $select-arrows-height, cover;
      background-position: center right $select-padding-x, center;
      appearance: none;
      background-color: #393E41;
      border: 1px solid #383c3f;
      box-shadow: 0px 0px 5px 1px rgba(0,0,0,0.5);
      color: #e4e4e6;
      border-radius: 4px;
      z-index: 1;
      opacity: 1;
      transition: opacity .2s;
      padding: {
        top: $select-padding-y;
        bottom: $select-padding-y;
        left: $select-padding-x;
        right: ($select-padding-x * 2) + $select-arrows-width;
      }
    }

    &.is-mobile {
      select {
        pointer-events: auto;
      }
    }

    &__options {
      box-sizing: border-box;
      position: absolute;
      width: 100%;
      top: calc(100% - 2px);
      left: 0;
      background-color: #2e3136;
      border-bottom-left-radius: 4px;
      border-bottom-right-radius: 4px;
      box-shadow: 0px 0px 5px 1px rgba(0,0,0,0.5);
      max-height: 350px;
      overflow-y: auto;
      color: #92959a;
      padding-top: 13px;
      padding-bottom: 10px;
      padding-left: $select-padding-x;
      padding-right: $select-padding-x;
      &:hover {
        cursor: default;
      }
      &__item {
        box-sizing: content-box;
        padding: $select-padding-y 0;
        position: relative;
        border-bottom: 1px solid #383c3f;
        &:last-child {
          border-bottom: none;
        }
        &:hover {
          cursor: pointer;
        }
        &.active, &:hover {
          color: #e4e4e6;
        }
      }
    }
  }
</style>
